content:
{
  "sentences": [
    {
      "text": "你好，我想要一杯小杯的拿鐵，可以嗎？",
      "pinyin": "Nǐ hǎo, wǒ xiǎng yào yī bēi xiǎo bēi de ná tiě, kě yǐ ma?",
      "pinyin_numeric": "ni3 hao3, wo3 xiang3 yao4 yi1 bei1 xiao3 bei1 de5 na2 tie3, ke3 yi3 ma0?",
      "translation_en": "Hello, I would like a small latte, okay?",
      "translation_ko": "안녕하세요, 작은 라떼 한 잔을 원하는데 괜찮을까요?"
    },
    {
      "text": "麻煩你，可以給我一個袋子嗎？",
      "pinyin": "Má fan nǐ, kě yǐ gěi wǒ yī ge dài zi ma?",
      "pinyin_numeric": "ma2 fan5 ni3, ke3 yi3 gei3 wo3 yi1 ge5 dai4 zi5 ma0?",
      "translation_en": "Excuse me, could you give me a bag?",
      "translation_ko": "실례합니다, 봉투 하나 주실 수 있나요?"
    },
    {
      "text": "不好意思，可以幫我看看菜單嗎？",
      "pinyin": "Bù hǎo yì si, kě yǐ bāng wǒ kàn kàn cài dān ma?",
      "pinyin_numeric": "bu4 hao3 yi4 si5, ke3 yi3 bang1 wo3 kan4 kan5 cai4 dan1 ma0?",
      "translation_en": "Excuse me, could you help me look at the menu?",
      "translation_ko": "죄송합니다, 메뉴 좀 봐 주실 수 있나요?"
    },
    {
      "text": "我想要一杯紅茶，半糖少冰，可以嗎？",
      "pinyin": "Wǒ xiǎng yào yī bēi hóng chá, bàn táng shǎo bīng, kě yǐ ma?",
      "pinyin_numeric": "wo3 xiang3 yao4 yi1 bei1 hong2 cha2, ban4 tang2 shao3 bing1, ke3 yi3 ma0?",
      "translation_en": "I would like a black tea, half sugar and less ice, okay?",
      "translation_ko": "홍차 한 잔, 반당에 얼음 적게 해 주실 수 있나요?"
    },
    {
      "text": "請問，這個價錢可以嗎？",
      "pinyin": "Qǐng wèn, zhè ge jià qián kě yǐ ma?",
      "pinyin_numeric": "qing3 wen4, zhe4 ge5 jia4 qian2 ke3 yi3 ma0?",
      "translation_en": "Excuse me, is this price okay?",
      "translation_ko": "실례합니다, 이 가격 괜찮나요?"
    },
    {
      "text": "可以給我一根吸管嗎？",
      "pinyin": "Kě yǐ gěi wǒ yī gēn xī guǎn ma?",
      "pinyin_numeric": "ke3 yi3 gei3 wo3 yi1 gen1 xi1 guan3 ma0?",
      "translation_en": "Could you give me a straw?",
      "translation_ko": "빨대 하나 주실 수 있나요?"
    },
    {
      "text": "不好意思，可以再說一次嗎？慢一點。",
      "pinyin": "Bù hǎo yì si, kě yǐ zài shuō yī cì ma? Màn yī diǎn.",
      "pinyin_numeric": "bu4 hao3 yi4 si5, ke3 yi3 zai4 shuo1 yi1 ci4 ma0? man4 yi1 dian3.",
      "translation_en": "Excuse me, could you say it again? Slower.",
      "translation_ko": "죄송합니다, 한 번 더 말씀해 주시겠어요? 천천히요."
    },
    {
      "text": "我想要一杯綠茶，內用，可以嗎？",
      "pinyin": "Wǒ xiǎng yào yī bēi lǜ chá, nèi yòng, kě yǐ ma?",
      "pinyin_numeric": "wo3 xiang3 yao4 yi1 bei1 lü4 cha2, nei4 yong4, ke3 yi3 ma0?",
      "translation_en": "I would like a green tea, for here, okay?",
      "translation_ko": "녹차 한 잔, 매장에서 마실게요, 괜찮을까요?"
    },
    {
      "text": "麻煩你，可以幫我加珍珠嗎？",
      "pinyin": "Má fan nǐ, kě yǐ bāng wǒ jiā zhēn zhū ma?",
      "pinyin_numeric": "ma2 fan5 ni3, ke3 yi3 bang1 wo3 jia1 zhen1 zhu1 ma0?",
      "translation_en": "Excuse me, could you add boba for me?",
      "translation_ko": "실례합니다, 타피오카 펄 추가해 주실 수 있나요?"
    },
    {
      "text": "不好意思，可以等一下嗎？我還要看菜單。",
      "pinyin": "Bù hǎo yì si, kě yǐ děng yī xià ma? Wǒ hái yào kàn cài dān.",
      "pinyin_numeric": "bu4 hao3 yi4 si5, ke3 yi3 deng3 yi1 xia4 ma0? wo3 hai2 yao4 kan4 cai4 dan1.",
      "translation_en": "Excuse me, could you wait a moment? I still need to look at the menu.",
      "translation_ko": "죄송합니다, 잠시만 기다려 주시겠어요? 메뉴를 더 봐야 해요."
    }
  ]
}
